mapper.update:
update employee
name = #{name}, account = #{account}, phone = #{phone}, age = #{age}, gender = #{gender}, pic = #{pic}, store_id = #{storeId}, role = #{role}, create_user = #{createUser}, update_user = #{updateUser}, create_time = #{createTime}, update_time = #{updateTime}
where id = #{id}

update employee

    password = #{password},
    update_time = #{updateTime}

where id = #{id}

mapper.select:
select e.*, s.name as store_name from employee e left join store s on e.store_id = s.id
and e.name like concat('%', #{name}, '%')
and e.store_id = #{storeId}
and e.role = #{role}
order by FIELD(e.role, '2', 'CHAIRMAN', '1', 'MANAGER', '0', 'EMPLOYEE') asc, e.id desc
